import React, { useEffect, useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { UserContext } from '../../context/User';
import { API, showError, showSuccess, showWarning, copy, timestamp2string } from '../../helpers';
import { Button } from '../../components/ui/button';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '../../components/ui/table';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '../../components/ui/dialog';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '../../components/ui/dropdown-menu';
import {
  BarChart3,
  Zap,
  Star,
  Plus,
  Copy,
  Ban,
  Trash2,
  AlertTriangle,
  ChevronLeft,
  ChevronRight,
  Eye,
  EyeOff,
} from 'lucide-react';

const ITEMS_PER_PAGE = 10;

const DashboardPage = () => {
  const { t } = useTranslation();
  const [userState] = useContext(UserContext);
  const username = userState.user?.username || 'Developer';

  // Stats
  const [quotaInfo, setQuotaInfo] = useState(null);
  const [dashboardData, setDashboardData] = useState([]);

  // API Key table
  const [tokens, setTokens] = useState([]);
  const [loading, setLoading] = useState(false);
  const [page, setPage] = useState(0);
  const [showKey, setShowKey] = useState({});
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState(null);

  useEffect(() => {
    loadStats();
  }, []);

  useEffect(() => {
    loadTokens();
  }, [page]); // eslint-disable-line react-hooks/exhaustive-deps

  const loadStats = async () => {
    try {
      const [quotaRes, dashRes] = await Promise.all([
        API.get('/api/subscription/quota'),
        API.get('/api/user/dashboard'),
      ]);
      if (quotaRes.data.success) setQuotaInfo(quotaRes.data.data);
      if (dashRes.data.success) setDashboardData(dashRes.data.data || []);
    } catch (err) {
      // silent
    }
  };

  const loadTokens = async () => {
    setLoading(true);
    try {
      const res = await API.get(`/api/token/?p=${page}`);
      if (res.data.success) {
        setTokens(res.data.data || []);
      } else {
        showError(res.data.message);
      }
    } catch (err) {
      showError(t('console.api_keys.load_failed'));
    }
    setLoading(false);
  };

  const toggleToken = async (id, status) => {
    const newStatus = status === 1 ? 2 : 1;
    try {
      const res = await API.put('/api/token/?status_only=true', { id, status: newStatus });
      if (res.data.success) {
        showSuccess(t('console.api_keys.status_updated'));
        loadTokens();
      } else {
        showError(res.data.message);
      }
    } catch (err) {
      showError(t('console.api_keys.operation_failed'));
    }
  };

  const deleteToken = async () => {
    if (!deleteTarget) return;
    try {
      const res = await API.delete(`/api/token/${deleteTarget}`);
      if (res.data.success) {
        showSuccess(t('console.api_keys.delete_success'));
        setDeleteDialogOpen(false);
        setDeleteTarget(null);
        loadTokens();
      } else {
        showError(res.data.message);
      }
    } catch (err) {
      showError(t('console.api_keys.delete_failed'));
    }
  };

  const maskKey = (key) => {
    if (!key) return '';
    if (key.length <= 10) return key;
    return key.substring(0, 7) + '****' + key.substring(key.length - 3);
  };

  const toggleShowKey = (id) => {
    setShowKey((prev) => ({ ...prev, [id]: !prev[id] }));
  };

  const getServerAddress = () => {
    let status = localStorage.getItem('status');
    let serverAddress = '';
    if (status) {
      status = JSON.parse(status);
      serverAddress = status.server_address;
    }
    if (serverAddress === '') {
      serverAddress = window.location.origin;
    }
    return serverAddress;
  };

  const onCopyKey = async (key) => {
    if (await copy(`sk-${key}`)) {
      showSuccess(t('console.common.copied'));
    } else {
      showWarning(t('console.api_keys.copy_failed'));
    }
  };

  const onCopyConfigLink = async (type, key) => {
    const serverAddress = getServerAddress();
    const chatLink = localStorage.getItem('chat_link');
    let url;
    switch (type) {
      case 'cursor':
        url = `OPENAI_API_KEY=sk-${key}\nOPENAI_BASE_URL=${serverAddress}/v1`;
        break;
      case 'claude-code':
        url = JSON.stringify({ name: 'Alaya Code', baseUrl: `${serverAddress}/anthropic/v1`, apiKey: `sk-${key}` }, null, 2);
        break;
      case 'next': {
        const nextBase = chatLink || 'https://app.nextchat.dev';
        url = nextBase + `/#/?settings={"key":"sk-${key}","url":"${serverAddress}"}`;
        break;
      }
      case 'lobechat': {
        const lobeBase = chatLink || '';
        url = lobeBase + `/?settings={"keyVaults":{"openai":{"apiKey":"sk-${key}","baseURL":"${serverAddress}/v1"}}}`;
        break;
      }
      default:
        url = `sk-${key}`;
    }
    if (await copy(url)) {
      showSuccess(t('console.common.copied'));
    } else {
      showWarning(t('console.api_keys.copy_failed'));
    }
  };

  // Compute stats
  const weekRequests = Array.isArray(dashboardData)
    ? dashboardData.reduce((sum, item) => sum + (item.RequestCount || 0), 0)
    : 0;

  const weeklyUsagePercent = quotaInfo?.weekly_limit_count
    ? Math.min(100, Math.round((weekRequests / quotaInfo.weekly_limit_count) * 100))
    : 0;

  const windowRemainPercent = quotaInfo?.window_limit_count
    ? Math.min(100, Math.round(((quotaInfo.window_remain_count || 0) / quotaInfo.window_limit_count) * 100))
    : 0;

  return (
    <div className='flex flex-col min-h-0'>
      {/* Page header */}
      <div className='bg-white px-6 py-5 border-b border-[#e1e7ef]'>
        <h1 className='text-2xl font-medium text-[#090e1a] leading-8'>
          欢迎回来，{username}
        </h1>
        <p className='text-base text-[#65758b] mt-1'>管理你的 API 资源</p>
      </div>

      {/* Content */}
      <div className='flex-1 overflow-y-auto p-6 space-y-6'>
        {/* 3 Stat Cards */}
        <div className='grid grid-cols-1 md:grid-cols-3 gap-4'>
          {/* Weekly usage */}
          <div className='bg-white border border-[#e1e7ef] p-5'>
            <div className='flex items-center gap-3 mb-3'>
              <div className='w-8 h-8 bg-[#f0f5ff] flex items-center justify-center'>
                <BarChart3 className='h-4 w-4 text-[#4362ff]' />
              </div>
              <span className='text-sm text-[#65758b]'>本周用量</span>
            </div>
            <div className='text-3xl font-semibold text-[#090e1a] font-mono'>{weeklyUsagePercent}%</div>
            <div className='mt-2 w-full h-1.5 bg-[#f1f5f9] rounded-full overflow-hidden'>
              <div
                className='h-full bg-[#4362ff] rounded-full transition-all'
                style={{ width: `${weeklyUsagePercent}%` }}
              />
            </div>
            <p className='text-xs text-[#9eacbf] mt-1'>
              已使用 {weekRequests} / {quotaInfo?.weekly_limit_count || '—'} 次
            </p>
          </div>

          {/* Rate limit remaining */}
          <div className='bg-white border border-[#e1e7ef] p-5'>
            <div className='flex items-center gap-3 mb-3'>
              <div className='w-8 h-8 bg-[#fff7e6] flex items-center justify-center'>
                <Zap className='h-4 w-4 text-[#faad14]' />
              </div>
              <span className='text-sm text-[#65758b]'>频限明细剩余</span>
            </div>
            <div className='text-3xl font-semibold text-[#090e1a] font-mono'>{windowRemainPercent}%</div>
            <div className='mt-2 w-full h-1.5 bg-[#f1f5f9] rounded-full overflow-hidden'>
              <div
                className='h-full bg-[#faad14] rounded-full transition-all'
                style={{ width: `${windowRemainPercent}%` }}
              />
            </div>
            <p className='text-xs text-[#9eacbf] mt-1'>
              剩余 {quotaInfo?.window_remain_count || 0} / {quotaInfo?.window_limit_count || '—'} 次
            </p>
          </div>

          {/* Current plan */}
          <div className='bg-white border border-[#e1e7ef] p-5'>
            <div className='flex items-center gap-3 mb-3'>
              <div className='w-8 h-8 bg-[#f6ffed] flex items-center justify-center'>
                <Star className='h-4 w-4 text-[#52c41a]' />
              </div>
              <span className='text-sm text-[#65758b]'>当前套餐</span>
            </div>
            <div className='text-2xl font-semibold text-[#090e1a] font-mono'>
              {quotaInfo?.plan_name || '—'}
            </div>
            <p className='text-xs text-[#9eacbf] mt-2'>
              {quotaInfo?.plan_name
                ? `${quotaInfo.window_limit_count || 0} 次/${Math.floor((quotaInfo.window_duration_sec || 3600) / 3600)}h 频限`
                : '暂无订阅'}
            </p>
            <Link to='/subscription' className='text-xs text-[#4362ff] hover:underline mt-1 inline-block no-underline'>
              查看详情 →
            </Link>
          </div>
        </div>

        {/* API Key Management */}
        <div className='bg-white border border-[#e1e7ef]'>
          {/* Section header */}
          <div className='flex items-center justify-between px-6 py-4 border-b border-[#e1e7ef]'>
            <div>
              <h2 className='text-lg font-medium text-[#090e1a]'>API Key 管理</h2>
              <p className='text-sm text-[#65758b]'>管理你的 API 调用密钥</p>
            </div>
            <Button
              className='bg-[#4362ff] hover:bg-[#3451e6] text-white h-9 px-4 text-sm'
              onClick={() => (window.location.href = '#/token/add')}
            >
              <Plus className='h-4 w-4 mr-1.5' />
              新建 Key
            </Button>
          </div>

          {/* Warning banner */}
          <div className='mx-6 mt-4 flex items-center gap-2 bg-[#fffbe6] border border-[#ffe58f] px-4 py-2.5'>
            <AlertTriangle className='h-4 w-4 text-[#faad14] flex-shrink-0' />
            <span className='text-sm text-[#8c6d1f]'>
              请妥善保管你的 API Key，不要分享给他人，避免在代码中硬编码。
            </span>
          </div>

          {/* Table */}
          <div className='px-6 py-4'>
            <Table>
              <TableHeader>
                <TableRow className='border-b border-[#e1e7ef] hover:bg-transparent'>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>名称</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>Key</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>状态</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>创建时间</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>创建人</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11 text-right'>操作</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  <TableRow>
                    <TableCell colSpan={6} className='text-center py-12 text-[#9eacbf]'>
                      加载中...
                    </TableCell>
                  </TableRow>
                ) : tokens.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={6} className='text-center py-12 text-[#9eacbf]'>
                      暂无 API Key
                    </TableCell>
                  </TableRow>
                ) : (
                  tokens.map((token) => (
                    <TableRow key={token.id} className='border-b border-[#e1e7ef] hover:bg-[#f8fafc]'>
                      <TableCell className='text-sm text-[#090e1a] font-medium'>
                        {token.name || '未命名'}
                      </TableCell>
                      <TableCell>
                        <div className='flex items-center gap-1.5'>
                          <code className='text-sm text-[#090e1a] font-mono'>
                            {showKey[token.id] ? `sk-${token.key}` : maskKey(`sk-${token.key}`)}
                          </code>
                          <button
                            className='p-1 hover:bg-[#f1f5f9] transition-colors border-0 bg-transparent cursor-pointer'
                            onClick={() => toggleShowKey(token.id)}
                          >
                            {showKey[token.id] ? (
                              <EyeOff className='h-3.5 w-3.5 text-[#9eacbf]' />
                            ) : (
                              <Eye className='h-3.5 w-3.5 text-[#9eacbf]' />
                            )}
                          </button>
                        </div>
                      </TableCell>
                      <TableCell>
                        {token.status === 1 ? (
                          <span className='inline-flex items-center gap-1.5 text-sm'>
                            <span className='w-1.5 h-1.5 rounded-full bg-[#52c41a]' />
                            <span className='text-[#090e1a]'>启用</span>
                          </span>
                        ) : (
                          <span className='inline-flex items-center gap-1.5 text-sm'>
                            <span className='w-1.5 h-1.5 rounded-full bg-[#9eacbf]' />
                            <span className='text-[#9eacbf]'>禁用</span>
                          </span>
                        )}
                      </TableCell>
                      <TableCell className='text-sm text-[#090e1a]'>
                        {timestamp2string(token.created_time)}
                      </TableCell>
                      <TableCell className='text-sm text-[#090e1a]'>
                        {username}
                      </TableCell>
                      <TableCell className='text-right'>
                        <div className='flex items-center justify-end gap-1'>
                          {/* Copy dropdown */}
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <button className='p-1.5 hover:bg-[#f1f5f9] transition-colors text-[#4362ff] border-0 bg-transparent cursor-pointer'>
                                <Copy className='h-3.5 w-3.5' />
                              </button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align='end'>
                              <DropdownMenuItem onClick={() => onCopyKey(token.key)}>
                                复制 Key
                              </DropdownMenuItem>
                              <DropdownMenuSeparator />
                              <DropdownMenuItem onClick={() => onCopyConfigLink('cursor', token.key)}>
                                Cursor 配置
                              </DropdownMenuItem>
                              <DropdownMenuItem onClick={() => onCopyConfigLink('claude-code', token.key)}>
                                Claude Code 配置
                              </DropdownMenuItem>
                              <DropdownMenuItem onClick={() => onCopyConfigLink('next', token.key)}>
                                NextChat 配置
                              </DropdownMenuItem>
                              <DropdownMenuItem onClick={() => onCopyConfigLink('lobechat', token.key)}>
                                LobeChat 配置
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>
                          {/* Toggle */}
                          <button
                            className='p-1.5 hover:bg-[#f1f5f9] transition-colors text-[#9eacbf] border-0 bg-transparent cursor-pointer'
                            onClick={() => toggleToken(token.id, token.status)}
                            title={token.status === 1 ? '禁用' : '启用'}
                          >
                            <Ban className='h-3.5 w-3.5' />
                          </button>
                          {/* Delete */}
                          <button
                            className='p-1.5 hover:bg-[#fff1f0] transition-colors text-[#ff4d4f] border-0 bg-transparent cursor-pointer'
                            onClick={() => {
                              setDeleteTarget(token.id);
                              setDeleteDialogOpen(true);
                            }}
                          >
                            <Trash2 className='h-3.5 w-3.5' />
                          </button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>

          {/* Pagination */}
          {tokens.length > 0 && (
            <div className='flex items-center justify-between px-6 py-3 border-t border-[#e1e7ef]'>
              <span className='text-sm text-[#9eacbf]'>
                第 {page + 1} 页
              </span>
              <div className='flex items-center gap-1'>
                <button
                  className='w-8 h-8 flex items-center justify-center border border-[#e1e7ef] hover:bg-[#f8fafc] disabled:opacity-40 disabled:cursor-not-allowed transition-colors bg-white cursor-pointer'
                  disabled={page === 0}
                  onClick={() => setPage((p) => Math.max(0, p - 1))}
                >
                  <ChevronLeft className='h-4 w-4 text-[#344256]' />
                </button>
                <button className='w-8 h-8 flex items-center justify-center border border-[#4362ff] bg-white text-[#4362ff] text-sm font-medium cursor-default'>
                  {page + 1}
                </button>
                <button
                  className='w-8 h-8 flex items-center justify-center border border-[#e1e7ef] hover:bg-[#f8fafc] disabled:opacity-40 disabled:cursor-not-allowed transition-colors bg-white cursor-pointer'
                  disabled={tokens.length < ITEMS_PER_PAGE}
                  onClick={() => setPage((p) => p + 1)}
                >
                  <ChevronRight className='h-4 w-4 text-[#344256]' />
                </button>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Delete dialog */}
      <Dialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>确认删除</DialogTitle>
            <DialogDescription>
              删除后该 API Key 将立即失效，无法恢复。确定继续？
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant='outline' onClick={() => setDeleteDialogOpen(false)}>
              取消
            </Button>
            <Button variant='destructive' onClick={deleteToken}>
              删除
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default DashboardPage;
